var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쓰러트렸어......?","JPN":"倒した……？","ENG":"He beat it?","TWN":"打倒了？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체를?","JPN":"第4種侵食体を？","ENG":"He beat a Category 4 C.O.?","TWN":"他把4類侵蝕體打倒了？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"여, 역시 델타세븐 최강의 전투요원답군요.","JPN":"さ、さすがデルタセブンきっての最強戦闘員。","ENG":"Y-you're Delta Seven's strongest combatant for a reason.","TWN":"不、不愧是第七三角洲的最強戰鬥要員。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대단하십니다, 소령님......","JPN":"すごすぎます、少佐……","ENG":"You're amazing, Major.","TWN":"太了不起了，少校大人……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":" 쿨럭! 쿨럭!","JPN":"ゲホッ！　ゲホッ！","ENG":" *Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아직 무리하지 마! 상처가 심하다고!","JPN":"まだ無理しちゃダメよ！　ひどいケガなんだから！","ENG":"Stop moving! You're badly wounded!","TWN":"你還不能太勉強！你的傷太重了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......놀라서 말이 안 나오는군.","JPN":"……こりゃ、驚きすぎて言葉も出てこないな。","ENG":"I'm so shocked that I'm at a loss for words.","TWN":"……我驚訝到都說不出話來了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"단독으로 제 4종 침식체를 격퇴하다니......","JPN":"単独で第4種侵食体を撃退するなんて……","ENG":"You singlehandedly beat a Category 4 C.O.","TWN":"竟然獨自擊退了4類侵蝕體……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"상부는 대체 왜 이런 부대의 정식 배치를 반대하는 거지?","JPN":"上層部はなぜこんな部隊の正規認定に反対するんだ？","ENG":"Why does the brass refuse to officially acknowledge such a strong unit?","TWN":"上面究竟為什麼反對將這樣的部隊轉為正式部隊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"일어설 수 있겠나?","JPN":"自力で立てそうか？","ENG":"Can you stand up?","TWN":"能站起來嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럭저럭......","JPN":"なんとかな……","ENG":"I think so.","TWN":"勉強還行吧……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"당신이 목숨을 걸어준 덕분에 등대의 핵심 부품을 지킬 수 있다고 들었어.","JPN":"君が体を張ってくれたおかげで、灯台のコアを守れたと聞いた。","ENG":"I heard you risked your life to protect the Lighthouse's core component.","TWN":"我聽說了多虧你拚上性命，我們才保住了燈塔的核心部件。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님 대신 감사를 표하지.","JPN":"司令官の代わりに礼をしたい。","ENG":"I'd like to thank you on behalf of the Commander.","TWN":"我代替司令官向你表示感謝。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"별거 아니야.","JPN":"大したことない。","ENG":"It's nothing.","TWN":"沒什麼。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그리고 감사라면 이쪽에서 해야지, 생명의 은인인데 말이야.","JPN":"それに感謝ならこっちがすべきだろ、命の恩人だからな。","ENG":"Besides, I should thank you. You saved my life.","TWN":"而且應該是我感謝你才對，你可是我的救命恩人。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그나저나 같이 간 길잡이는 어떻게 됐나? 보이질 않는데.","JPN":"それより同行した道案内役はどこだ？　見当たらないんだが。","ENG":"By the way, what happened to your guide? I don't see him anywhere.","TWN":"不過和你一起去的帶路人怎麼樣了？我怎麼沒看到他。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......나도 모르겠군. 갑자기 사라졌어.","JPN":"……俺にもわからない。急に消えちまったんだ。","ENG":"Beats me. He disappeared all of a sudden.","TWN":"……我也不知道，他突然消失了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"덕분에 돌아오는 시간도 늦어졌고.","JPN":"そのせいで帰還も遅れてしまった。","ENG":"That's why it took me so long to come back.","TWN":"拜他所賜，我也晚了很久才回來。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"길잡이가 사라져? 설마 그 뺀질이가 또......","JPN":"道案内役が消えただと？　まさか、あのサボり魔がまた……","ENG":"He disappeared? God, that slacker...","TWN":"突然消失了？那個滑頭該不會又……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하아, 뭐 대충 예상되는군.","JPN":"はあ……まあ、心当たりはある。","ENG":"*Sigh* I think I know what happened.","TWN":"唉，雖然也大概預想到了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"오해 말라고. 정보부에 다 그런 멍청이만 있는 건 아니니까.","JPN":"誤解するな。情報局はあんなマヌケ野郎ばかりいるわけじゃないぞ。","ENG":"But please don't think everyone in the Intelligence Agency is as cowardly as he is.","TWN":"請不要誤會。情報部並不是只有那種蠢貨。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"적어도 한 명 정도는 그런 것 같군.","JPN":"少なくとも一名は確定っぽいがな。","ENG":"I know at least one of them isn't.","TWN":"看來至少有一位是這樣沒錯。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......이건 정보부답지 않은 용맹한 분투에 대한 감사의 표시야. 받아두라고.","JPN":"……これは情報局らしくない勇敢な戦いへのお礼だ。受け取っておけ。","ENG":"This is my token of gratitude for your bravery that has changed my impression of you spies. Keep it.","TWN":"……這是對你不符合情報部的勇敢奮鬥，所表達的感謝。收下吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이건...... 작전 코드잖아?","JPN":"これは……作戦コードじゃないか？","ENG":"It's... an operation code.","TWN":"這……這不是作戰代碼嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"프리덤 스트라이크......?","JPN":"フリーダムストライク……？","ENG":"Freedom Strike?","TWN":"自由之擊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"뭔가, 이 매우 합중국스러운 이름은?","JPN":"なんだ、この限りなくアメリカンな名前は？","ENG":"What's this star-spangled name?","TWN":"總覺得，有點像聯邦政府的名字？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님이 국방부에 제안한 긴급 함대 지원 코드야.","JPN":"司令官が国防省に提案した緊急艦隊支援コードだ。","ENG":"It's an emergency fleet support code that the Commander has suggested to the Department of Defense.","TWN":"這是司令官向國防部提案的緊急艦隊支援代碼。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이번처럼 이면세계에서 긴급 상황 발생 시 즉각적으로 함대 지원을 받을 수 있지.","JPN":"今回のように裏世界で緊急事態が発生した際、すみやかに艦隊支援を受けることができる。","ENG":"It provides immediate fleet support in case of emergency in the Counterside, like this.","TWN":"要是像這次一樣，在異界發生了緊急情況時，就可以立即獲得艦隊的支援。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아직은 검토단계지만 곧 실전배치 될 거야.","JPN":"まだ検討段階だが、まもなく実戦に配置されるだろう。","ENG":"It's still being reviewed, but will be implemented soon.","TWN":"雖然現在還在研討階段，但很快就會配備在實戰中了吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"혹시라도 위험에 처하거나 하면 사용하라고. 내가 도와주러 갈 테니.","JPN":"もしも危険に瀕した場合はこれを使え。俺が助けに行ってやる。","ENG":"Use it when you're in danger. I'll come to help you.","TWN":"萬一之後你陷入危機時，就可以使用它。我會來幫你的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그거 든든하군.","JPN":"そりゃ心強い。","ENG":"That's good to know.","TWN":"那還真是可靠啊。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하지만 난 이제 이면세계 쪽 작전은 사양이라서 말이야.","JPN":"けど、私は裏世界での作戦はもう御免だ。","ENG":"But I think I'm done with Counterside operations.","TWN":"不過我現在已經拒絕再到異界作戰了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"내가 사용할 일이 있을까 싶지만...... 호의는 받아 두지.","JPN":"使うことがあるかわからないが……誠意は受け取っておこう。","ENG":"I doubt I'll ever use it, but still I'll keep it.","TWN":"雖然我覺得沒什麼機會用到它……但還是收下你的好意吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"고맙네.","JPN":"ありがとう。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"어, 어이!!","JPN":"お、おい！！","ENG":"H-hey!","TWN":"喂、喂！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"다들 용케 살아남았나 보군! 잘했어!","JPN":"みんなよくぞ生き延びたな！　すばらしいぞ！","ENG":"You all have survived! Good!","TWN":"看來大家都順利活下來了！幹得好！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L44_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"제이콥? 대체 어디에 있다가 이제야 온 건가?","JPN":"ジェイコブ？　いったい今までどこにいたんだ？","ENG":"Jacob? Where the hell have you been?","TWN":"雅各？你到底去哪裡了，怎麼現在才來？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"몰라서 물어? 상대는 제 4종 침식체라고!","JPN":"そりゃ決まってるだろ？　相手は第4種侵食体なんだ！","ENG":"Do you have to ask? It was a Category 4 C.O.!","TWN":"你是不知道才這麼問嗎？對手可是4類侵蝕體啊！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"그런 게 나타났는데 멍청하게 앞에서 얼쩡거릴 수는 없잖아?","JPN":"あんなのが現れたのに、その前でウロチョロするバカがいるか？","ENG":"I wasn't going to wait around until it decided to kill me!","TWN":"出現了那種玩意，我不可能傻乎乎地在它面前磨蹭吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"파괴된 침식 쐐기 근처에서 몸을 숨기고 있었지.","JPN":"破壊された侵食楔の近くに身を隠してたんだよ。","ENG":"I was hiding behind a destroyed Corrupted Wedge.","TWN":"我當然是躲到被破壞的侵蝕釘附近去啦。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......그러니까 다른 동료들이 목숨 걸고 싸우는 동안 숨어 있었다고?","JPN":"……つまり、仲間が命がけで戦っている間、隠れていたと？","ENG":"You were hiding while your teammates risked their lives fighting it?","TWN":"……所以，在其他同伴們拚上性命戰鬥的時候，你躲了起來？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......여기에도 용병 못지않은 버러지가 있긴 하군.","JPN":"……ここにも傭兵に引けを取らないクズがいやがる。","ENG":"You're just as shameless as mercenaries.","TWN":"……這裡也有不輸給傭兵的垃圾呢。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"시끄러워! 멍청한 군바리 놈이 뭐라는 거야?","JPN":"うるせえ！　マヌケな軍人野郎が何をほざく？","ENG":"Shut up! I don't need a lecture from stupid GIs like you.","TWN":"吵死了！你這蠢貨在說什麼呢？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"자고로 정보부 요원에겐 바퀴벌레 같은 생명력이 미덕이라고!","JPN":"昔っから情報局員といえば、ゴキブリ並みの生命力が誇りなんだぜ！","ENG":"Nothing's more important to us intelligence agents than survival. We're hard to kill, just like cockroaches!","TWN":"自古以來，小強一樣的生命力就是情報部要員的美德！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"그보다 전출 추천서 써주기로 한 약속은 잊지 않았겠지?","JPN":"それより、出向推薦書の約束は忘れてないよな？","ENG":"By the way, you didn't forget your promise to write me a letter of recommendation, right?","TWN":"話說回來，你說好要給我寫推薦信的，沒忘記吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"크악! 왜 때리는 거야?!","JPN":"いてえ！　なぜ叩く！？","ENG":"Wah! Why did you hit me?!","TWN":"唔啊！你幹嘛打我啊？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......바퀴벌레처럼 살아남으라고 했지, 언제 바퀴벌레가 되라고 했냐! 이 멍청아!","JPN":"……それはゴキブリのようにしぶとく生き延びろってことだろ。\\nゴキブリそのものになってどうすんだ、このバカ野郎！","ENG":"You're supposed to survive like a cockroach—not to become a cockroach itself! You fool!","TWN":"……我只說要像小強一樣活下去，什麼時候說要你變成小強了！你這白癡！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"돌아가면 징계위원회에 할 변명이나 생각해 두라고.","JPN":"戻ったら懲戒委員会に何て釈明するか考えておけよ。","ENG":"You'd better have a good excuse to give to the Disciplinary Committee when we go back.","TWN":"你回去後，就想想要怎麼和懲戒委員會辯解吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그쪽도 고충이 많나 보군.","JPN":"そっちも色々大変なんだな。","ENG":"You have a full plate.","TWN":"看來你也有很多苦衷啊。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"어디든 안 그런 곳이 있겠나?","JPN":"問題を抱えない組織なんてあるもんか。","ENG":"Just like everyone else.","TWN":"哪裡有什麼沒苦衷的地方？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그나저나 격퇴하긴 했지만 제 4종 침식체까지 나타나다니......","JPN":"それより、撃退はできたが第4種侵食体まで現れるとは……","ENG":"By the way, even though you beat it, I can't believe a Category 4 C.O. showed up.","TWN":"不過我們雖然擊退了敵人，但沒想到連4類侵蝕體都出現了……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"대체 저 안에서 무슨 일이 벌어지고 있는 건지 모르겠군.","JPN":"いったいあの中で何が起きてるんだろうか。","ENG":"What the hell is going on in there?","TWN":"不知道那裡面到底發生了什麼事。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};